+const QUIPS = [
+  'For the realm!', 'By decree...', 'Hmm...', 'The scrolls speak.', 'Guards!',
+  'Fascinating.', 'Another day...', 'The kingdom grows.', 'To battle!',
+  'Justice prevails.', 'The forge calls.', 'Heal thyself.'
+];
+
+interface Bubble { text: string; timer: number; kind: 'speech' | 'thought' }
+const bubbles = new Map<string, Bubble>();
+
+function updateBubble(id: string, state: AnimState, job: string | null, frame: number) {
+  const b = bubbles.get(id);
+  if (b) {
+    b.timer--;
+    if (b.timer <= 0) bubbles.delete(id);
+    return;
+  }
+  if (state === 'working' && job && frame % 300 < 2) {
+    const text = job.length > 28 ? job.substring(0, 26) + '..' : job;
+    bubbles.set(id, { text, timer: 180, kind: 'speech' });
+  } else if (state === 'idle' && frame % 500 < 2) {
+    const text = QUIPS[Math.floor(Math.random() * QUIPS.length)];
+    bubbles.set(id, { text, timer: 180, kind: 'thought' });
+  }
+}
+
+function drawBubble(ctx: CanvasRenderingContext2D, id: string, x: number, y: number) {
+  const b = bubbles.get(id);
+  if (!b) return;
+  ctx.globalAlpha = b.timer < 30 ? b.timer / 30 : 1;
+  ctx.font = '9px monospace';
+  const tw = ctx.measureText(b.text).width;
+  const paddingX = 6, paddingY = 6;
+  const bw = tw + paddingX * 2, bh = 20;
+  const bx = x - bw / 2, by = y - bh - 10;
+
+  // Background fill and border
+  ctx.fillStyle = '#fff';
+  ctx.strokeStyle = '#222';
+  ctx.lineWidth = 1;
+  roundRect(ctx, bx, by, bw, bh, 6);
+  ctx.fill();
+  ctx.stroke();
+
+  // Pointer triangle
+  ctx.beginPath();
+  ctx.moveTo(x - 6, by + bh);
+  ctx.lineTo(x, by + bh + 8);
+  ctx.lineTo(x + 6, by + bh);
+  ctx.closePath();
+  ctx.fill();
+  ctx.stroke();
+
+  // Text
+  ctx.fillStyle = '#000';
+  ctx.fillText(b.text, bx + paddingX, by + bh - paddingY);
+
+  ctx.globalAlpha = 1;
+}
+
+function roundRect(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, r: number) {
+  ctx.beginPath();
+  ctx.moveTo(x + r, y);
+  ctx.lineTo(x + w - r, y);
+  ctx.quadraticCurveTo(x + w, y, x + w, y + r);
+  ctx.lineTo(x + w, y + h - r);
+  ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
+  ctx.lineTo(x + r, y + h);
+  ctx.quadraticCurveTo(x, y + h, x, y + h - r);
+  ctx.lineTo(x, y + r);
+  ctx.quadraticCurveTo(x, y, x + r, y);
+  ctx.closePath();
+}
